import{c as a,Q as n,j as s,m as t}from"./chunks/framework.CdiUUa3G.js";const u=JSON.parse('{"title":"UXS-003 — Mission Arc","description":"","frontmatter":{},"headers":[],"relativePath":"uxs/UXS-003.md","filePath":"uxs/UXS-003.md"}'),i={name:"uxs/UXS-003.md"};function o(r,e,l,c,d,p){return n(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="uxs-003-—-mission-arc" tabindex="-1">UXS-003 — Mission Arc <a class="header-anchor" href="#uxs-003-—-mission-arc" aria-label="Permalink to &quot;UXS-003 — Mission Arc&quot;">​</a></h1><blockquote><p>Status · Draft v0.1 Visual fidelity · Verified against prototype (P03_mission-arc.html) IA anchor · §surfaces/fly · §topbar-patterns · §shared-tokens Related PRD · PRD-003 Related ADRs · ADR-009 (free-return), ADR-010 (Keplerian arcs) Related RFCs · RFC-002 (events schema), RFC-004 (URL sharing)</p></blockquote><h2 id="why-this-uxs-exists" tabindex="-1">Why this UXS exists <a class="header-anchor" href="#why-this-uxs-exists" aria-label="Permalink to &quot;Why this UXS exists&quot;">​</a></h2><p>The fly screen has the most complex layout of any screen — dual HUD panels, timeline scrubber, CAPCOM panels, and a full-viewport 3D or 2D canvas. This UXS defines the static appearance of all components and the visual distinction between outbound and return arcs.</p><h2 id="principles" tabindex="-1">Principles <a class="header-anchor" href="#principles" aria-label="Permalink to &quot;Principles&quot;">​</a></h2><ul><li>The spacecraft is always visible and identifiable</li><li>Past trajectory is solid; future is dashed — the distinction is immediate</li><li>Outbound arc (blue) and return arc (violet) are distinguishable without a legend</li><li>HUD panels are readable at a glance — data, not decoration</li><li>CAPCOM mode adds information without hiding the canvas</li></ul><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>In scope: nav bar, 3D scene, 2D canvas, HUD panels (left identity, right navigation, right systems), CAPCOM panels, timeline scrubber, bottom bar, milestone markers (FLYBY, RETURN), spacecraft icon. Non-goals: animation easing, CAPCOM panel slide-in timing. Boundary note: CAPCOM event triggering logic belongs in the screen module.</p><h2 id="theme" tabindex="-1">Theme <a class="header-anchor" href="#theme" aria-label="Permalink to &quot;Theme&quot;">​</a></h2><p>Dark only.</p><h2 id="tokens" tabindex="-1">Tokens <a class="header-anchor" href="#tokens" aria-label="Permalink to &quot;Tokens&quot;">​</a></h2><h3 id="inherited-from-ia" tabindex="-1">Inherited from IA <a class="header-anchor" href="#inherited-from-ia" aria-label="Permalink to &quot;Inherited from IA&quot;">​</a></h3><p>All shared tokens.</p><h3 id="defined-here" tabindex="-1">Defined here <a class="header-anchor" href="#defined-here" aria-label="Permalink to &quot;Defined here&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>arc-outbound:      rgba(68,102,255,0.75)   past, solid</span></span>
<span class="line"><span>arc-outbound-fut:  rgba(68,102,255,0.20)   future, dashed</span></span>
<span class="line"><span>arc-return:        rgba(123,156,255,0.75)  past, solid</span></span>
<span class="line"><span>arc-return-fut:    rgba(123,156,255,0.20)  future, dashed</span></span>
<span class="line"><span>flyby-marker:      rgba(193,68,14,0.8)     Mars red crosshair</span></span>
<span class="line"><span>return-marker:     rgba(75,156,211,0.8)    Earth blue crosshair</span></span>
<span class="line"><span>spacecraft-fill:   rgba(255,255,255,0.95)  chevron fill</span></span>
<span class="line"><span>spacecraft-border: rgba(68,102,255,0.8)    chevron stroke</span></span>
<span class="line"><span>hud-left-accent:   #4466ff</span></span>
<span class="line"><span>hud-right-accent:  #4ecdc4</span></span>
<span class="line"><span>hud-sys-accent:    #ff9940</span></span>
<span class="line"><span>capcom-accent:     rgba(0,220,80,0.7)</span></span></code></pre></div><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><h3 id="hud-panels-2d-and-3d" tabindex="-1">HUD panels (2D and 3D) <a class="header-anchor" href="#hud-panels-2d-and-3d" aria-label="Permalink to &quot;HUD panels (2D and 3D)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>LEFT (identity, 225px):         RIGHT-TOP (navigation, 228px):</span></span>
<span class="line"><span>┌─────────────────────┐         ┌──────────────────────┐</span></span>
<span class="line"><span>│ ▌ EARTH → MARS FLY  │         │ ▌ NAVIGATION          │</span></span>
<span class="line"><span>│   ORRERY-1          │         │   Heliocentric vel.   │</span></span>
<span class="line"><span>│   Falcon Heavy      │         │   Distance from Earth │</span></span>
<span class="line"><span>│   Date / MET        │         │   Distance from Mars  │</span></span>
<span class="line"><span>└─────────────────────┘         │   Signal delay / Sun  │</span></span>
<span class="line"><span>                                 └──────────────────────┘</span></span>
<span class="line"><span>                                 RIGHT-BOTTOM (systems, 228px):</span></span>
<span class="line"><span>                                 ┌──────────────────────┐</span></span>
<span class="line"><span>                                 │ ▌ SYSTEMS             │</span></span>
<span class="line"><span>                                 │   Propellant bar      │</span></span>
<span class="line"><span>                                 │   Δv remaining bar    │</span></span>
<span class="line"><span>                                 │   ETA / Phase         │</span></span>
<span class="line"><span>                                 └──────────────────────┘</span></span></code></pre></div><h3 id="capcom-panels-left-side-222px-shown-when-capcom-active" tabindex="-1">CAPCOM panels (left side, 222px, shown when CAPCOM active) <a class="header-anchor" href="#capcom-panels-left-side-222px-shown-when-capcom-active" aria-label="Permalink to &quot;CAPCOM panels (left side, 222px, shown when CAPCOM active)&quot;">​</a></h3><p>Three stacked panels replacing the left identity panel:</p><ol><li>Mission events ticker (max-height 190px, scrollable)</li><li>Communications (signal delay, RTT, DSN contact)</li><li>Anomaly monitor (nominal / caution / critical)</li></ol><h3 id="timeline-scrubber-bottom-bar-68px" tabindex="-1">Timeline scrubber (bottom bar, 68px) <a class="header-anchor" href="#timeline-scrubber-bottom-bar-68px" aria-label="Permalink to &quot;Timeline scrubber (bottom bar, 68px)&quot;">​</a></h3><p>Play/pause button · speed controls (1d/s, 7d/s, 30d/s, 90d/s) · scrubber track · MET display</p><h3 id="spacecraft-icon" tabindex="-1">Spacecraft icon <a class="header-anchor" href="#spacecraft-icon" aria-label="Permalink to &quot;Spacecraft icon&quot;">​</a></h3><p>2D: white chevron (triangle with cut tail, 9px half-size) oriented along velocity vector, blue glow behind. 3D: cone (nose) + cylinder (body) + inverted cone (nozzle), oriented along velocity vector.</p><h2 id="component-states" tabindex="-1">Component states <a class="header-anchor" href="#component-states" aria-label="Permalink to &quot;Component states&quot;">​</a></h2><p><strong>Arc (outbound, past):</strong> solid blue 1.5px line <strong>Arc (outbound, future):</strong> dashed blue 20% opacity, [5,5] dash pattern <strong>Arc (return, past):</strong> solid violet 1.5px <strong>Arc (return, future):</strong> dashed violet 20%, [5,5] <strong>Flyby ring (near Mars, progress 0.45–0.55):</strong> pulsing red ring, opacity 0.3–0.7 <strong>Flyby ring (all other times):</strong> hidden <strong>CAPCOM button (inactive):</strong> <code>border rgba(78,205,196,0.7)</code>, <code>bg rgba(78,205,196,0.12)</code>, <code>color #4ecdc4</code><strong>CAPCOM button (active):</strong> <code>border #4ecdc4</code>, <code>bg rgba(78,205,196,0.22)</code>, <code>color #fff</code>, <code>box-shadow 0 0 10px rgba(78,205,196,0.4)</code><strong>Anomaly (nominal):</strong> <code>border rgba(40,40,40,1)</code>, <code>color rgba(78,205,196,0.7)</code>, text &quot;ALL SYSTEMS NOMINAL&quot; <strong>Anomaly (caution):</strong> <code>border rgba(255,200,80,0.5)</code>, <code>color #ffc850</code>, text &quot;⚠ CAUTION: FUEL LOW&quot; <strong>Anomaly (critical):</strong> <code>border rgba(255,80,80,0.6)</code>, <code>color #ff6060</code>, blinking, text &quot;⚠ CRITICAL&quot;</p><h2 id="accessibility" tabindex="-1">Accessibility <a class="header-anchor" href="#accessibility" aria-label="Permalink to &quot;Accessibility&quot;">​</a></h2><ul><li>Canvas screens: <code>aria-label</code> describing the mission arc view</li><li>CAPCOM panels: HTML content, screen-reader accessible</li><li><code>prefers-reduced-motion</code>: freeze simTime, disable auto-orbit</li></ul><h2 id="acceptance-criteria" tabindex="-1">Acceptance criteria <a class="header-anchor" href="#acceptance-criteria" aria-label="Permalink to &quot;Acceptance criteria&quot;">​</a></h2><ul><li>[ ] Outbound arc renders in blue; return arc renders in violet</li><li>[ ] Past trajectory solid; future trajectory dashed</li><li>[ ] Flyby marker visible only near Mars (progress 0.45–0.55)</li><li>[ ] RETURN marker visible at Earth arrival position</li><li>[ ] Spacecraft chevron oriented along velocity direction in 2D</li><li>[ ] Spacecraft rocket shape visible and oriented in 3D</li><li>[ ] CAPCOM button click shows/hides CAPCOM panels</li><li>[ ] Mission event ticker scrolls; past events shown, oldest faded</li><li>[ ] Signal delay updates from actual Earth distance</li><li>[ ] Anomaly monitor transitions: nominal → caution → critical at fuel thresholds</li><li>[ ] Timeline scrubber thumb tracks progress; drag works</li><li>[ ] Speed buttons highlight active speed</li></ul><hr><h2 id="extension-—-flight-params-hud-readout-v0-1-7-adr-027" tabindex="-1">Extension — Flight params HUD readout (v0.1.7 / ADR-027) <a class="header-anchor" href="#extension-—-flight-params-hud-readout-v0-1-7-adr-027" aria-label="Permalink to &quot;Extension — Flight params HUD readout (v0.1.7 / ADR-027)&quot;">​</a></h2><p>When the loaded mission has a populated <code>flight</code> sub-object, /fly&#39;s HUD surfaces real per-mission flight parameters instead of the synthesised defaults.</p><h3 id="layout-addition" tabindex="-1">Layout addition <a class="header-anchor" href="#layout-addition" aria-label="Permalink to &quot;Layout addition&quot;">​</a></h3><p>A new <strong>FLIGHT PARAMS</strong> group sits below the existing NAV HUD on the left rail:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>LAUNCH C3        11.2 km²/s²</span></span>
<span class="line"><span>ARRIVAL V∞        5.6 km/s</span></span>
<span class="line"><span>TOTAL ∆v          6.1 km/s     [src: NASA MSL Press Kit]</span></span></code></pre></div><p>Source citation collapses on phones (≤767 px) into a tap-to-reveal tooltip on the row.</p><h3 id="sparse-data-caveat-banner" tabindex="-1">Sparse-data caveat banner <a class="header-anchor" href="#sparse-data-caveat-banner" aria-label="Permalink to &quot;Sparse-data caveat banner&quot;">​</a></h3><p>When <code>flight_data_quality !== &quot;measured&quot;</code>, a one-line banner sits above FLIGHT PARAMS, amber tint (<code>#ffc850</code> border, <code>rgba(255,200,80,0.18)</code> bg). Plain-language copy is i18n-keyed.</p><h3 id="missing-values" tabindex="-1">Missing values <a class="header-anchor" href="#missing-values" aria-label="Permalink to &quot;Missing values&quot;">​</a></h3><p>Render as <code>—</code> (em-dash). Never as <code>0</code> or <code>null</code>. Never invent a plausible-sounding default.</p><h3 id="arc-geometry-hook" tabindex="-1">Arc geometry hook <a class="header-anchor" href="#arc-geometry-hook" aria-label="Permalink to &quot;Arc geometry hook&quot;">​</a></h3><p>If <code>flight.arrival.v_infinity_km_s</code> is present, the outbound arc&#39;s terminal segment uses it (not the Lambert-default V∞) so two missions to the same destination on the same dates render visibly distinct paths when their target geometry differs. Falls back to the v0.1.6 Lambert geometry when absent.</p><h3 id="tokens-extension" tabindex="-1">Tokens (extension) <a class="header-anchor" href="#tokens-extension" aria-label="Permalink to &quot;Tokens (extension)&quot;">​</a></h3><p><strong>FLIGHT PARAMS group bg:</strong> <code>rgba(20,30,55,0.72)</code> matching existing HUD tint <strong>FLIGHT PARAMS label:</strong> Space Mono, 10 px, <code>rgba(180,200,255,0.85)</code><strong>FLIGHT PARAMS value:</strong> Space Mono, 13 px, accent per-row (∆v <code>#ffc850</code>, V∞ <code>#4ecdc4</code>, C3 <code>#4b9cd3</code>) <strong>Caveat banner:</strong> <code>#ffc850</code> border 1 px, <code>rgba(255,200,80,0.18)</code> bg, 12 px Space Mono uppercase</p><h3 id="acceptance-criteria-extension" tabindex="-1">Acceptance criteria (extension) <a class="header-anchor" href="#acceptance-criteria-extension" aria-label="Permalink to &quot;Acceptance criteria (extension)&quot;">​</a></h3><ul><li>[ ] When <code>mission.flight</code> is present, FLIGHT PARAMS group renders below NAV</li><li>[ ] When <code>mission.flight</code> is absent, no FLIGHT PARAMS group appears (no regression)</li><li>[ ] When <code>flight_data_quality !== &quot;measured&quot;</code>, caveat banner shows</li><li>[ ] Missing fields render as <code>—</code>, never as <code>0</code> or <code>undefined</code></li><li>[ ] Source citation accessible (visible desktop, tooltip mobile)</li><li>[ ] Arc terminal uses real V∞ when present</li></ul>`,48)])])}const b=a(i,[["render",o]]);export{u as __pageData,b as default};
